	cur := left
	prev := left
	var halfErr error
	for _, t := range rest.([]any) {
		tail := t.(infixTail)
		if tail.half && halfErr == nil {
			halfErr = halfSpacedError(tail.op, prev, tail.right)
		}
		prev = tail.right
		cur = &Infix{S: cur.Span(), Op: tail.op, Left: cur, Right: tail.right}
	}
	return cur, halfErr
